import React, { useEffect, useState } from 'react';
import { RPHModule } from '../types';

interface ModalProps {
  module: RPHModule | null;
  onClose: () => void;
  children?: React.ReactNode;
}

const Modal: React.FC<ModalProps> = ({ module, onClose, children }) => {
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    if (module) {
      setTimeout(() => setIsVisible(true), 10);
      document.body.style.overflow = 'hidden';
    } else {
      setIsVisible(false);
      document.body.style.overflow = 'auto';
    }
  }, [module]);

  if (!module) return null;

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300);
  };

  return (
    <div 
      className={`fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6 transition-opacity duration-300 ${isVisible ? 'opacity-100' : 'opacity-0'}`}
      style={{ backgroundColor: 'rgba(0, 0, 0, 0.75)', backdropFilter: 'blur(4px)' }}
      onClick={handleClose}
    >
      <div 
        className={`bg-white w-full max-w-4xl max-h-[90vh] rounded-3xl overflow-hidden shadow-2xl flex flex-col transition-transform duration-300 ${isVisible ? 'translate-y-0 scale-100' : 'translate-y-12 scale-95'}`}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="bg-slate-50 px-8 py-6 border-b border-slate-100 flex items-center justify-between sticky top-0 z-20">
          <div className="flex items-center gap-6">
            <span className="text-5xl">{module.icon}</span>
            <div>
              <h2 className="text-2xl font-bold text-slate-800">{module.title}</h2>
              <span className="text-sm font-medium text-slate-400">{module.articles}</span>
            </div>
          </div>
          <button 
            onClick={handleClose}
            className="text-slate-300 hover:text-red-500 transition-colors text-4xl leading-none p-2"
          >
            &times;
          </button>
        </div>

        {/* Content */}
        <div className="flex-grow overflow-y-auto p-8 scroll-smooth">
          {children ? (
            children
          ) : (
            <div className="space-y-8">
              {module.sections.map((section, idx) => {
                const typeStyles = {
                  info: 'border-blue-400 bg-blue-50 text-blue-900',
                  warning: 'border-amber-400 bg-amber-50 text-amber-900',
                  danger: 'border-red-400 bg-red-50 text-red-900 font-medium',
                  success: 'border-green-400 bg-green-50 text-green-900',
                }[section.type || 'info'];

                return (
                  <div key={idx} className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <h4 className="text-lg font-bold text-slate-700 border-b-2 border-slate-100 pb-2 mb-4 flex items-center gap-2">
                      <span className="w-1.5 h-6 bg-blue-500 rounded-full"></span>
                      {section.title}
                    </h4>

                    {section.type ? (
                      <div className={`p-4 rounded-xl border-l-4 ${typeStyles} shadow-sm`}>
                        {Array.isArray(section.content) ? (
                          <ul className="space-y-2">
                            {section.content.map((item, i) => (
                              <li key={i} className="flex gap-2">
                                <span className="text-current opacity-70 mt-1">●</span>
                                <span>{item}</span>
                              </li>
                            ))}
                          </ul>
                        ) : (
                          <p className="leading-relaxed">{section.content}</p>
                        )}
                      </div>
                    ) : (
                      <div className="text-slate-600 leading-relaxed">
                        {Array.isArray(section.content) ? (
                          <ul className="space-y-3">
                            {section.content.map((item, i) => (
                              <li key={i} className="flex gap-3">
                                <span className="text-green-500 font-bold">✓</span>
                                <span>{item}</span>
                              </li>
                            ))}
                          </ul>
                        ) : (
                          <p>{section.content}</p>
                        )}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Modal;

import React, { useState } from 'react';
import { askGemini } from '../services/geminiService';
import { AITab } from '../types';

const AIAssistant: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AITab>('consultas');
  const [input, setInput] = useState('');
  const [result, setResult] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const handleGenerate = async () => {
    if (!input.trim()) return;

    setIsLoading(true);
    setResult('');
    setError('');

    try {
      const response = await askGemini(input, activeTab);
      setResult(response);
    } catch (err) {
      setError('Hubo un error al conectar con el asistente. Por favor verifica tu conexión o intenta más tarde.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl w-fit">
        <button 
          onClick={() => setActiveTab('consultas')}
          className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${activeTab === 'consultas' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:bg-white/50'}`}
        >
          🔍 Consultar Reglamento
        </button>
        <button 
          onClick={() => setActiveTab('cartas')}
          className={`px-6 py-2 rounded-xl text-sm font-bold transition-all ${activeTab === 'cartas' ? 'bg-white shadow-sm text-purple-600' : 'text-slate-500 hover:bg-white/50'}`}
        >
          📝 Redactar Carta
        </button>
      </div>

      <div className="space-y-4">
        <p className="text-slate-600 text-sm italic">
          {activeTab === 'consultas' 
            ? 'Pregunta dudas sobre mascotas, ruidos, parqueaderos, multas o asambleas.' 
            : 'Describe tu situación y la IA redactará una carta formal lista para enviar a la administración.'}
        </p>

        <textarea 
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder={activeTab === 'consultas' ? 'Ejemplo: ¿Es legal que el Consejo cambie el color de la fachada sin asamblea?' : 'Ejemplo: Soy del apto 305 y tengo una filtración hace 2 semanas que no han reparado.'}
          className="w-full h-32 p-4 rounded-2xl border-2 border-slate-100 focus:border-blue-400 focus:ring-0 outline-none transition-all resize-none text-slate-800"
        />

        <button 
          onClick={handleGenerate}
          disabled={isLoading || !input.trim()}
          className={`w-full py-4 rounded-2xl flex items-center justify-center gap-3 font-bold text-white transition-all shadow-lg hover:shadow-xl active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed ${activeTab === 'consultas' ? 'bg-blue-600' : 'gemini-gradient'}`}
        >
          {isLoading ? (
            <>
              <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
              <span>Procesando...</span>
            </>
          ) : (
            <>
              <span>{activeTab === 'consultas' ? 'Preguntar a la IA' : 'Generar Documento'}</span>
              <span>✨</span>
            </>
          )}
        </button>
      </div>

      {(result || error) && (
        <div className={`mt-8 p-6 rounded-2xl animate-in fade-in slide-in-from-top-4 duration-500 ${error ? 'bg-red-50 border border-red-100' : 'bg-slate-50 border border-slate-100'}`}>
          <div className="flex items-center gap-2 mb-4">
            <span className="font-bold text-slate-800 uppercase text-xs tracking-widest flex items-center gap-2">
              <span className={`w-2 h-2 rounded-full ${error ? 'bg-red-500' : 'bg-green-500'}`}></span>
              Respuesta del Asistente
            </span>
          </div>
          {error ? (
            <p className="text-red-600 text-sm font-medium">{error}</p>
          ) : (
            <div className="prose prose-slate max-w-none">
              <p className="text-slate-700 whitespace-pre-wrap leading-relaxed text-[1.05rem]">{result}</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default AIAssistant;

