interface CardProps {
  module: RPHModule;
  onClick: (module: RPHModule) => void;
}

const Card: React.FC<CardProps> = ({ module, onClick }) => {
  const [hovered, setHovered] = useState(false);

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: { opacity: 1 },
  };

  const initialCardStyle = {
    opacity: 0,
    transform: 'translateY(10px)',
  };

  const hoveredCardStyle = {
    opacity: 1,
    transform: 'translateY(0)',
    transition: {
      duration: 0.3,
      ease: 'easeInOut',
