  const aiContent = {
    opacity: 0,
    y: 10,
    transition: {
      duration: 0.3,
      ease: 'easeInOut',
    },
  };

  return (
    <motion.div
      initial={initialCardStyle}
      animate={hovered ? hoveredCardStyle : initialCardStyle}
      className="relative w-full p-4 bg-white rounded-lg shadow-md hover:shadow-xl focus:shadow-xl transition-shadow duration-300 ease-in-out"
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onFocus={() => setHovered(true)}
      onBlur={() => setHovered(false)}
      tabIndex={0}
      style={{
        background: hovered ? 'linear-gradient(135deg, #6C63FF 0%, #76B4FF 100%)' : 'rgba(255, 255, 255, 0.15)',
      }}
    >
      <AnimatePresence>
        {hovered ? (
          <motion.div>
            <motion.h2 variants={containerVariants} initial="hidden" animate="visible" className="text-xl font-bold mb-2 text-white">
              {module.title}
            </motion.h2>
            <motion.p variants={aiContent} initial="hidden" animate="visible" className="text-gray-200 mb-4">
              {module.description}
            </motion.p>
            <motion.button
              variants={aiContent}
              initial="hidden"
              animate="visible"
              className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded"
              onClick={() => onClick(module)}
            >
              {module.buttonText}
            </motion.button>
          </motion.div>
